const body = $input.first().json.body;
const tipo = body.tipo || '';

let message = '';
if (tipo === 'assessment' || body.nome) {
  const parts = [];
  if (body.nome) parts.push('Nome: ' + body.nome);
  if (body.idade) parts.push('Idade: ' + body.idade);
  if (body.escolaridade) parts.push('Escolaridade: ' + body.escolaridade);
  if (body.experiencia) parts.push('Experiencia: ' + body.experiencia);
  if (body.hardSkills && body.hardSkills.length) parts.push('Hard Skills: ' + body.hardSkills.join(', '));
  if (body.softSkills && body.softSkills.length) parts.push('Soft Skills: ' + body.softSkills.join(', '));
  if (body.tecnologias && body.tecnologias.length) parts.push('Tecnologias: ' + body.tecnologias.join(', '));
  message = 'Avaliacao de carreira para: ' + parts.join(' | ');
} else if (tipo === 'mental-health' || body.userId) {
  message = body.message || 'Avaliacao de saude mental para usuario ' + (body.userId || 'desconhecido');
} else {
  message = body.message || JSON.stringify(body);
}

return [{ json: { message: message, tipo: tipo, originalBody: body } }];
